25: // Interface for getting values from a cookie or a header.
26: class ValueSelector {
27: public:
28:   virtual ~ValueSelector() = default;
29: 
30:   /**
31:    * Called to extract the value of a given header or cookie.
32:    * @param http header map.
33:    * @return absl::optional<std::string> the extracted header or cookie.
34:    */
35:   virtual absl::optional<std::string> extract(Http::HeaderMap& map) const PURE;
36: 
37:   /**
38:    * @return a string representation of either a cookie or a header passed in the request.
39:    */
40:   virtual std::string toString() const PURE;
41: };
42: 
43: // Get value from a header.
44: class HeaderValueSelector : public ValueSelector {
45: public:
46:   // ValueSelector.
47:   explicit HeaderValueSelector(Http::LowerCaseString header, bool remove)
48:       : header_(std::move(header)), remove_(std::move(remove)) {}
49:   absl::optional<std::string> extract(Http::HeaderMap& map) const override;
50:   std::string toString() const override { return fmt::format("header '{}'", header_.get()); }
51:   ~HeaderValueSelector() override = default;
52: 
53: private:
54:   const Http::LowerCaseString header_;
55:   const bool remove_;
56: };
57: 
58: // Get value from a cookie.
59: class CookieValueSelector : public ValueSelector {
60: public:
61:   // ValueSelector.
62:   explicit CookieValueSelector(std::string cookie) : cookie_(std::move(cookie)) {}
63:   absl::optional<std::string> extract(Http::HeaderMap& map) const override;
64:   std::string toString() const override { return fmt::format("cookie '{}'", cookie_); }
65:   ~CookieValueSelector() override = default;
66: 
67: private:
68:   const std::string cookie_;
69: };
