75:   const Regex::CompiledMatcherPtr& regexRewrite() const { return regex_rewrite_; }
76:   const std::string& regexSubstitution() const { return regex_rewrite_substitution_; }
77:   std::shared_ptr<const ValueSelector> selector_;
78: 
79: private:
80:   const ProtoRule rule_;
81:   Regex::CompiledMatcherPtr regex_rewrite_{};
82:   std::string regex_rewrite_substitution_{};
83: };
