  EXPECT_EQ(Http::FilterHeadersStatus::Continue, filter_->encodeHeaders(response_headers, false));
  EXPECT_EQ("response-value", response_headers.get("x-response-header"));
}

/**
 * Test empty configuration.
 */
TEST_F(CustomHeaderInjectionTest, EmptyConfig) {
  const std::string config_yaml = "{}";

  initializeFilter(config_yaml);
  Http::TestRequestHeaderMapImpl headers;

  EXPECT_EQ(Http::FilterHeadersStatus::Continue, filter_->decodeHeaders(headers, false));
}

/**
 * Test header overwriting.
 */
TEST_F(CustomHeaderInjectionTest, OverwriteExistingHeader) {
  const std::string config_yaml = R"EOF(
request_headers:
  x-header: new-value
)EOF";

  initializeFilter(config_yaml);
  Http::TestRequestHeaderMapImpl headers{{"x-header", "old-value"}};

  EXPECT_EQ(Http::FilterHeadersStatus::Continue, filter_->decodeHeaders(headers, false));
  EXPECT_EQ("new-value", headers.get("x-header"));
}

/**
 * Test onDestroy.
 */
TEST_F(CustomHeaderInjectionTest, OnDestroy) {
  const std::string config_yaml = R"EOF(
request_headers:
  x-header: value
)EOF";

  initializeFilter(config_yaml);
  filter_->onDestroy();
}

/**
 * Test data and trailer handling.
 */
TEST_F(CustomHeaderInjectionTest, DataAndTrailerHandling) {
  const std::string config_yaml = "{}";

  initializeFilter(config_yaml);

  Buffer::OwnedImpl data("test data");
  EXPECT_EQ(Http::FilterDataStatus::Continue, filter_->decodeData(data, false));

  Http::TestRequestTrailerMapImpl trailers;
  EXPECT_EQ(Http::FilterTrailersStatus::Continue, filter_->decodeTrailers(trailers));

  Http::TestResponseTrailerMapImpl response_trailers;
  EXPECT_EQ(Http::FilterTrailersStatus::Continue, filter_->encodeTrailers(response_trailers));
}

